At" DATETIME,    "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,    "updatedAt" DATETIME NOT NULL,    CONSTRAINT "EmailCampaign_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User" ("id") ON DELETE CASCADE ON UPDATE CASCADE,    CONSTRAINT "EmailCampaign_templateId_fkey" FOREIGN KEY ("templateId") REFERENCES "EmailTemplate" ("id") ON DELETE SET NULL ON UPDATE CASCADE);-- CreateTableCREATE TABLE "EmailSendLog" (    "id" TEXT NOT NULL PRIMARY KEY,    "campaignId" TEXT NOT NULL,    "companyName" TEXT NOT NULL,    "hrEmail" TEXT NOT NULL,    "hrName" TEXT,    "jobTitle" TEXT NOT NULL,    "jobUrl" TEXT,    "renderedBody" TEXT NOT NULL,    "renderedSubj" TEXT NOT NULL,    "status" TEXT NOT NULL DEFAULT 'queued',    "errorMessage" TEXT,    "sentAt" DATETIME,    "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,    CONSTRAINT "EmailSendLog_campaignId_fkey" FOREIGN KEY ("campaignId") REFERENCES "EmailCampaign" ("id") ON DELETE CASCADE ON UPDATE CASCADE);-- CreateTableCREATE TABLE "Account" (    "userId" TEXT NOT NULL,    "type" TEXT NOT NULL,    "provider" TEXT NOT NULL,    "providerAccountId" TEXT NOT NULL,    "refresh_token" TEXT,    "access_token" TEXT,    "expires_at" INTEGER,    "token_type" TEXT,    "scope" TEXT,    "id_token" TEXT,    "session_state" TEXT,    PRIMARY KEY ("provider", "providerAccountId"),    CONSTRAINT "Account_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User" ("id") ON DELETE CASCADE ON UPDATE CASCADE);-- CreateTableCREATE TABLE "Session" (    "sessionToken" TEXT NOT NULL PRIMARY KEY,    "userId" TEXT NOT NULL,    "expires" DATETIME NOT NULL,    CONSTRAINT "Session_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User" ("id") ON DELETE CASCADE ON UPDATE CASCADE);-- CreateTableCREATE TABLE "VerificationToken" (    "identifier" TEXT NOT NULL,    "token" TEXT NOT NULL,    "expires" DATETIME NOT NULL,    PRIMARY KEY ("identifier", "token"));-- CreateIndexCREATE UNIQUE INDEX "User_email_key" ON "User"("email");-- CreateIndexCREATE INDEX 